+    let encryptedKey;
+    try {
+        encryptedKey = Buffer.from(encryptedKeyB64, 'base64');
+    }
+    catch {
+        return { ok: false, error: 'Edge Local State contains an invalid encrypted_key.' };
+    }
+    const prefix = Buffer.from('DPAPI', 'utf8');
